1	use crate::{
2	    Lint, Token, TokenKind,
3	    expr::{Expr, SequenceExpr},
4	    linting::{ExprLinter, LintKind, Suggestion, expr_linter::Chunk},
5	};
6	
7	pub struct BrandBrandish {
8	    expr: SequenceExpr,
9	}
10	
11	impl Default for BrandBrandish {
12	    fn default() -> Self {
13	        Self {
14	            expr: SequenceExpr::word_set(&["brandish", "brandished", "brandishes", "brandishing"])
15	                .t_ws()
16	                // "her" is also a possessive determiner as in "she brandished her sword"
17	                // "it" and "them" can refer to objects as in "draw your sword(s) and brandish it/them"
18	                .then_kind_except(TokenKind::is_object_pronoun, &["her", "it", "them"]),
19	        }
20	    }
21	}
22	
23	impl ExprLinter for BrandBrandish {
24	    type Unit = Chunk;
25	
26	    fn expr(&self) -> &dyn Expr {
27	        &self.expr
28	    }
29	
30	    fn match_to_lint(&self, toks: &[Token], src: &[char]) -> Option<Lint> {
31	        let verb_span = toks.first()?.span;
32	        let verb_chars = verb_span.get_content(src);
33	
34	        enum Form {
35	            Base,
36	            Past,
37	            ThirdPerson,
38	            Ing,
39	        }
40	
41	        let infl = match verb_chars.last().map(|c| c.to_ascii_lowercase()) {
42	            Some('h') => Form::Base,
43	            Some('d') => Form::Past,
44	            Some('s') => Form::ThirdPerson,
45	            Some('g') => Form::Ing,
46	            _ => return None,
47	        };
48	
49	        Some(Lint {
50	            span: verb_span,
51	            lint_kind: LintKind::Malapropism,
52	            suggestions: vec![Suggestion::replace_with_match_case_str(
53	                match infl {
54	                    Form::Base => "brand",
55	                    Form::Past => "branded",
56	                    Form::ThirdPerson => "brands",
57	                    Form::Ing => "branding",
58	                },
59	                verb_chars,
60	            )],
61	            message: "`Brandish` means to wield a weapon. You probably mean `brand`.".to_string(),
62	            ..Default::default()
63	        })
64	    }
65	
66	    fn description(&self) -> &str {
67	        "Looks for `brandish` wrongly used when `brand` is intended."
68	    }
69	}
70	
71	#[cfg(test)]
72	mod tests {
73	    use crate::linting::{brand_brandish::BrandBrandish, tests::assert_suggestion_result};
74	
75	    #[test]
76	    fn correct_brandish_a_traitor() {
77	        assert_suggestion_result(
78	            "Unretire Gretzky's sweater . Brandish him a traitor.",
79	            BrandBrandish::default(),
80	            "Unretire Gretzky's sweater . Brand him a traitor.",
81	        );
82	    }
83	
84	    #[test]
85	    fn correct_brandish_a_criminal() {
86	        assert_suggestion_result(
87	            "lied to stop kuma's ideology from taking root and to brandish him a criminal that they could arrest",
88	            BrandBrandish::default(),
89	            "lied to stop kuma's ideology from taking root and to brand him a criminal that they could arrest",
90	        );
91	    }
92	
93	    #[test]
94	    fn correct_brandish_as_a() {
95	        assert_suggestion_result(
96	            "he was so afraid his thoughts could brandish him as a paedophile",
97	            BrandBrandish::default(),
98	            "he was so afraid his thoughts could brand him as a paedophile",
99	        );
100	    }
101	
102	    #[test]
103	    fn correct_brandish_an_offender() {
104	        assert_suggestion_result(
105	            "Chanel Oberlin's reason for purposely leading on Pete Martinez in order to humiliate him and brandish him a registered sex offender",
106	            BrandBrandish::default(),
107	            "Chanel Oberlin's reason for purposely leading on Pete Martinez in order to humiliate him and brand him a registered sex offender",
108	        );
109	    }
110	
111	    #[test]
112	    fn correct_brandish_with_nicknames() {
113	        assert_suggestion_result(
114	            "?? spoke out over the move by Kenyans to continuously brandish him with nicknames even after ...",
115	            BrandBrandish::default(),
116	            "?? spoke out over the move by Kenyans to continuously brand him with nicknames even after ...",
117	        );
118	    }
119	
120	    #[test]
121	    fn correct_brandish_as_a_aymbol() {
122	        assert_suggestion_result(
123	            "brandish him as an acclaimed symbol of humility, integrity and incorruptibility in the face of today's corrupt economic and political elite1",
124	            BrandBrandish::default(),
125	            "brand him as an acclaimed symbol of humility, integrity and incorruptibility in the face of today's corrupt economic and political elite1",
126	        );
127	    }
128	
129	    #[test]
130	    fn correct_brandish_as_illegal() {
131	        assert_suggestion_result(
132	            "To attempt to brandish him as an “illegal immigrant” is absolutely ridiculous and warrants an immediate retraction and apology.",
133	            BrandBrandish::default(),
134	            "To attempt to brand him as an “illegal immigrant” is absolutely ridiculous and warrants an immediate retraction and apology.",
135	        );
136	    }
137	
138	    #[test]
139	    fn correct_brandish_with_nickname() {
140	        assert_suggestion_result(
141	            "The small minded townsfolk brandish him with the nickname \"Genepool\" due to his physical and cognitive shortcomings.",
142	            BrandBrandish::default(),
143	            "The small minded townsfolk brand him with the nickname \"Genepool\" due to his physical and cognitive shortcomings.",
144	        );
