        /// Add a `Linter` that requires a `Dialect` to the group, setting it to be enabled or disabled.
        macro_rules! insert_struct_rule_with_dialect {
            ($rule:ident, $default_config:expr) => {
                out.add(stringify!($rule), $rule::new(dialect));
