use crate::{
    CharStringExt, Lint, Token,
    expr::{Expr, SequenceExpr},
    linting::{ExprLinter, LintKind, Suggestion, expr_linter::Chunk},
};

pub struct FlauntFlout {
    expr: SequenceExpr,
}

impl Default for FlauntFlout {
    fn default() -> Self {
        Self {
            expr: SequenceExpr::word_set(&["flaunt", "flaunted", "flaunts", "flaunting"])
                .t_ws()
                .then_word_set(&[
                    "law",
                    "laws",
                    "regulation",
                    "regulations",
                    "rule",
                    "rules",
                ]),
        }
    }
}

impl FlauntFlout {
    fn to_correct(word: &str) -> Option<&'static str> {
        Some(match word.to_ascii_lowercase().as_str() {
            "flaunt" => "flout",
            "flaunted" => "flouted",
            "flaunts" => "flouts",
            "flaunting" => "flouting",
            _ => return None,
        })
    }
}

impl ExprLinter for FlauntFlout {
    type Unit = Chunk;

    fn expr(&self) -> &dyn Expr {
        &self.expr
    }

    fn match_to_lint(&self, toks: &[Token], src: &[char]) -> Option<Lint> {
        let verb_span = toks.first()?.span;
        let verb_chars = verb_span.get_content(src);
        let correct = Self::to_correct(&verb_chars.iter().collect::<String>())?;

        Some(Lint {
            span: verb_span,
            lint_kind: LintKind::WordChoice,
            suggestions: vec![Suggestion::replace_with_match_case_str(correct, verb_chars)],
            message:
                "`Flaunt` means to show off. Did you mean `flout`, as in openly disregard rules?"
                    .to_string(),
            priority: 31,
        })
    }

    fn description(&self) -> &'static str {
        "Detects incorrect usage of `flaunt` where `flout` is intended, as in `flaunt the rules`."
    }
}

#[cfg(test)]
mod tests {
    use super::FlauntFlout;
    use crate::linting::tests::{assert_lint_count, assert_suggestion_result};

    #[test]
    fn corrects_flaunted_laws() {
        assert_suggestion_result(
            "He flaunted bankruptcy laws for personal gain.",
            FlauntFlout::default(),
            "He flouted bankruptcy laws for personal gain.",
        );
    }

    #[test]
    fn corrects_flaunts_rules() {
        assert_suggestion_result(
            "The captain flaunts the rules.",
            FlauntFlout::default(),
            "The captain flouts the rules.",
        );
    }

    #[test]
    fn corrects_flaunting_laws() {
        assert_suggestion_result(
            "That's what deranged scientists flaunting the laws of God and Man are for.",
            FlauntFlout::default(),
            "That's what deranged scientists flouting the laws of God and Man are for.",
        );
    }

    #[test]
    fn corrects_flaunt_rules() {
        assert_suggestion_result(
            "Some seem to flaunt the basic rules of punctuation and grammar.",
            FlauntFlout::default(),
            "Some seem to flout the basic rules of punctuation and grammar.",
        );
    }

    #[test]
    fn does_not_correct_showing_off() {
        assert_lint_count(
            "The peacock seemed to flaunt its feathers.",
            FlauntFlout::default(),
            0,
        );
    }

    #[test]
    fn does_not_correct_flout() {
        assert_lint_count(
            "The captain flouts the rules.",
            FlauntFlout::default(),
            0,
        );
    }
}

